1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	const CURSED_SURCHARGE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
5	const HIGH_ENCHANTMENT_THRESHOLD = 5;
6	const LOYALTY_DISCOUNT_RATE = 0.2;
7	const LOYALTY_YEARS_THRESHOLD = 2;
8	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
9	const ALIKE_BLOCK_SIZE = 3;
10	const ALIKE_BLOCK_PREMIUM = 60;
11	const DEDUCTIBLE = 100;
12	const CAP_MULTIPLIER = 2;
13	
14	const BASE_PREMIUM: Record<string, number> = {
15	  sword: 100,
16	  amulet: 60,
17	  staff: 80,
18	  potion: 40,
19	  rune: 25,
20	  moonstone: 25,
21	};
22	
23	const INSURANCE_VALUE: Record<string, number> = {
24	  sword: 1000,
25	  amulet: 600,
26	  staff: 800,
27	  potion: 400,
28	  rune: 250,
29	  moonstone: 250,
30	};
31	
32	type Item = { type: string; cursed?: boolean; enchantment?: number; material?: string };
33	type Damage = { itemType: string; amount: number };
34	type Incident = { cause: string; damages: Damage[] };
35	type QuoteStep = { op: "quote"; items: Item[] };
36	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
37	type Step = QuoteStep | ClaimStep;
38	type Customer = { yearsWithMHPCO: number };
39	type Scenario = { customer: Customer; steps: Step[] };
40	type Policy = { items: Item[]; cap: number };
41	
42	const basePremiumOf = (item: Item): number => BASE_PREMIUM[item.type];
43	
44	const groupByType = (items: Item[]): Item[][] => {
45	  const groups = Map.groupBy(items, (item) => item.type);
46	  return Array.from(groups.values());
47	};
48	
49	const sumBasePremiums = (items: Item[]): number =>
50	  items.reduce((acc, item) => acc + basePremiumOf(item), 0);
51	
52	const basePremiumForGroup = (group: Item[]): number =>
53	  group.length === ALIKE_BLOCK_SIZE ? ALIKE_BLOCK_PREMIUM : sumBasePremiums(group);
54	
55	const basePremiumForItems = (items: Item[]): number =>
56	  groupByType(items).reduce((sum, group) => sum + basePremiumForGroup(group), 0);
57	
58	const cursedSurcharge = (item: Item): number =>
59	  item.cursed ? basePremiumOf(item) * CURSED_SURCHARGE_RATE : 0;
60	
61	const highEnchantmentSurcharge = (item: Item): number =>
62	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
63	    ? basePremiumOf(item) * HIGH_ENCHANTMENT_SURCHARGE_RATE
64	    : 0;
65	
66	const itemSurcharges = (items: Item[]): number =>
67	  items.reduce(
68	    (sum, item) => sum + cursedSurcharge(item) + highEnchantmentSurcharge(item),
69	    0,
70	  );
71	
72	const firstInsuranceSurcharge = (basePremium: number): number =>
73	  basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
74	
75	const loyaltyDiscount = (basePremium: number, customer: Customer): number =>
76	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? basePremium * LOYALTY_DISCOUNT_RATE : 0;
77	
78	const followUpDiscount = (basePremium: number, isFollowUp: boolean): number =>
79	  isFollowUp ? basePremium * FOLLOW_UP_DISCOUNT_RATE : 0;
80	
81	const quotePremium = (items: Item[], customer: Customer, isFollowUp: boolean): number => {
82	  const basePremium = basePremiumForItems(items);
83	  return (
84	    Math.ceil(
85	      basePremium +
86	        itemSurcharges(items) +
87	        firstInsuranceSurcharge(basePremium) -
88	        loyaltyDiscount(basePremium, customer) -
89	        followUpDiscount(basePremium, isFollowUp),
90	    ) + PROCESSING_FEE
91	  );
92	};
93	
94	const insuranceSum = (items: Item[]): number =>
95	  items.reduce((sum, item) => sum + INSURANCE_VALUE[item.type], 0);
96	
97	const damagePayout = (damage: Damage): number => damage.amount - DEDUCTIBLE;
98	
99	const processClaim = (policy: Policy, incident: Incident): { payout: number; remainingCap: number } => {
100	  const payout = incident.damages.reduce((sum, d) => sum + damagePayout(d), 0);
101	  return { payout, remainingCap: policy.cap - payout };
102	};
103	
104	export const runScenario = (scenario: Scenario): unknown => {
105	  const policies: Policy[] = [];
106	  let quoteIndex = 0;
107	  const results = scenario.steps.map((step) => {
108	    if (step.op === "quote") {
109	      const isFollowUp = quoteIndex > 0;
110	      quoteIndex++;
111	      policies.push({ items: step.items, cap: insuranceSum(step.items) * CAP_MULTIPLIER });
112	      return { premium: quotePremium(step.items, scenario.customer, isFollowUp) };
113	    }
114	    return processClaim(policies[step.policy], step.incident);
115	  });
116	  return { results };
117	};
